import React, { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import { ArrowLeft, ArrowRight } from 'lucide-react';

function TestimonialCarousel() {
  const [currentIndex, setCurrentIndex] = useState(0);
  const testimonials = [
    {
      text: 'TechForge has been instrumental in helping us scale our business.',
      author: 'John Doe, CEO of XYZ Corporation',
      image: 'https://images.unsplash.com/photo-1498050108023-c5249f4df085?auto=format&fit=crop&w=800&q=80',
    },
    {
      text: 'Their team is knowledgeable, responsive, and always willing to help.',
      author: 'Jane Smith, Marketing Manager at ABC Inc.',
      image: 'https://images.unsplash.com/photo-1519710166579-443d8d64572e?auto=format&fit=crop&w=800&q=80',
    },
    {
      text: 'Weve seen a significant increase in sales since partnering with TechForge.',
      author: 'Bob Johnson, Sales Director at DEF Ltd.',
      image: 'https://images.unsplash.com/photo-1518806118471-f28b20b6b3ce?auto=format&fit=crop&w=800&q=80',
    },
  ];

  useEffect(() => {
    const intervalId = setInterval(() => {
      setCurrentIndex((currentIndex + 1) % testimonials.length);
    }, 5000);
    return () => clearInterval(intervalId);
  }, [currentIndex, testimonials.length]);

  const handlePrevClick = () => {
    setCurrentIndex((currentIndex - 1 + testimonials.length) % testimonials.length);
  };

  const handleNextClick = () => {
    setCurrentIndex((currentIndex + 1) % testimonials.length);
  };

  return (
    <section className="bg-zinc-100 py-12 md:py-24 lg:py-36">
      <div className="container mx-auto flex flex-col items-center justify-center">
        <h2 className="text-3xl font-bold text-zinc-900 mb-4 md:mb-6 lg:mb-8">
          What Our Clients Say
        </h2>
        <div className="flex flex-col items-center justify-center space-y-4 md:space-y-6 lg:space-y-8">
          <motion.div
            initial={{ opacity: 0, scale: 0.5 }}
            animate={{ opacity: 1, scale: 1 }}
            transition={{ duration: 1 }}
            className="w-full h-full bg-zinc-100/50 rounded-md p-4 md:p-6 lg:p-8"
          >
            <p className="text-zinc-600 text-lg md:text-xl lg:text-2xl mb-4 md:mb-6 lg:mb-8">
              {testimonials[currentIndex].text}
            </p>
            <p className="text-zinc-600 text-lg md:text-xl lg:text-2xl">
              {testimonials[currentIndex].author}
            </p>
            <img
              src={testimonials[currentIndex].image}
              alt="Testimonial Image"
              className="w-full h-full object-cover rounded-md mt-4 md:mt-6 lg:mt-8"
            />
          </motion.div>
          <div className="flex justify-center space-x-4">
            <button
              className="bg-zinc-100 text-zinc-900 py-2 px-4 rounded-md hover:bg-zinc-200 transition duration-300"
              onClick={handlePrevClick}
            >
              <ArrowLeft size={16} className="mr-2" />
              Previous
            </button>
            <button
              className="bg-zinc-100 text-zinc-900 py-2 px-4 rounded-md hover:bg-zinc-200 transition duration-300"
              onClick={handleNextClick}
            >
              Next
              <ArrowRight size={16} className="ml-2" />
            </button>
          </div>
        </div>
      </div>
    </section>
  );
}

export default TestimonialCarousel;
